app.post('/authorize', (req, res) => {
  const {
    client_id,
    redirect_uri,
    scope,
    state,
    username,
    password,
    authorize,
    code_challenge,
    code_challenge_method
  } = req.body;

  if (!validateRedirectUri(client_id, redirect_uri)) {
    return res.status(400).json({ error: 'invalid_redirect_uri' });
  }

  const redirectUrl = new URL(redirect_uri);

  if (authorize !== 'true') {
    redirectUrl.searchParams.append('error', 'access_denied');
    if (state) redirectUrl.searchParams.append('state', state);
    return res.redirect(redirectUrl.toString());
  }

  if (!users[username] || users[username].password !== password) {
    redirectUrl.searchParams.append('error', 'access_denied');
    redirectUrl.searchParams.append('error_description', 'Invalid credentials');
    if (state) redirectUrl.searchParams.append('state', state);
    return res.redirect(redirectUrl.toString());
  }

  const authorizationCode = generateSecureToken(32);
  const codeData = {
    clientId: client_id,
    redirectUri: redirect_uri,
    scope: scope || '',
    username: username,
    expiresAt: Date.now() + CODE_EXPIRY,
    used: false,
    codeChallenge: code_challenge || null,
    codeChallengeMethod: code_challenge_method || null
  };

  authorizationCodes.set(authorizationCode, codeData);

  redirectUrl.searchParams.append('code', authorizationCode);
  if (state) redirectUrl.searchParams.append('state', state);

  res.redirect(redirectUrl.toString());
});

app.post('/token', (req, res) => {
  const {
    grant_type,
    code,
    redirect_uri,
    client_id,
    client_secret,
    code_verifier
  } = req.body;

  const authHeader = req.headers.authorization;
  let clientIdAuth = client_id;
  let clientSecretAuth = client_secret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const credentials = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const [id, secret] = credentials.split(':');
    clientIdAuth = id;
    clientSecretAuth = secret;
  }

  if (grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'code is required' });
  }

  const codeData = authorizationCodes.get(code);

  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid authorization code' });
  }

  if (codeData.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code already used' });
  }

  if (Date.now() > codeData.expiresAt) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
  }

  if (codeData.clientId !== clientIdAuth) {
    return res.status(400).json({ error: 'invalid_client', error_description: 'Client mismatch' });
  }

  if (!clients[clientIdAuth] || clients[clientIdAuth].clientSecret !== clientSecretAuth) {
    return res.status(401).json({ error: 'invalid_client', error_description: 'Invalid client credentials' });
  }

  if (codeData.redirectUri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  if (codeData.codeChallenge) {
    if (!code_verifier) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'code_verifier required' });
    }

    const hash = crypto.createHash('sha256').update(code_verifier).digest('base64url');
    
    if (hash !== codeData.codeChallenge) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid code_verifier' });
    }
  }

  codeData.used = true;
  authorizationCodes.delete(code);

  const accessToken = generateSecureToken(32);
  const refreshToken = generateSecureToken(32);

  accessTokens.set(accessToken, {
    clientId: clientIdAuth,
    username: codeData.username,
    scope: codeData.scope,
    expiresAt: Date.now() + TOKEN_EXPIRY
  });

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: TOKEN_EXPIRY / 1000,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
});

